/// <summary>
/// Construye LedgerDimensions de tipo NO contabilidad.
/// </summary>
class IFRDimensionLedgerDimensionBuilderNonLedger extends IFRDimensionLedgerDimensionBuilderBase
{
    LedgerJournalACType ledgerJournalACType;

}

Method.Source:
protected void new(LedgerJournalAC _ledgerJournalAC, LedgerJournalACType _ledgerJournalACType)
{
    ledgerJournalAC = _ledgerJournalAC;
    ledgerJournalACType = _ledgerJournalACType;
}

public static IFRDimensionLedgerDimensionBuilderNonLedger construct(LedgerJournalAC _ledgerJournalAC, LedgerJournalACType _ledgerJournalACType)
{
    IFRDimensionLedgerDimensionBuilderNonLedger IFRDimensionLedgerDimensionBuilderNonLedger;

    IFRDimensionLedgerDimensionBuilderNonLedger = new IFRDimensionLedgerDimensionBuilderNonLedger(_ledgerJournalAC, _ledgerJournalACType);

    return IFRDimensionLedgerDimensionBuilderNonLedger;
}

/// <summary>
/// Obtiene el LedgerDimension que hemos construido.
/// </summary>
/// <returns>LedgerDimensionAccount</returns>
public LedgerDimensionAccount getLedgerDimension()
{
    return LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber(ledgerJournalAC, ledgerJournalACType);
}

/// <summary>
/// Convierte un LedgerDimension a una cadena de texto separada por un separador (-).
/// </summary>
/// <returns>Cadena de texto con las dimensiones separadas por guión,</returns>
public str ToString()
{
    return ledgerJournalAC;
}
